#include <stdio.h>
#include <stdlib.h>
int main(){
    int N,M; if(scanf("%d %d",&N,&M)!=2) return 0;
    int *pref = (int*)calloc((N+1)*(M+1), sizeof(int));
    for(int i=1;i<=N;i++){
        for(int j=1;j<=M;j++){
            int v; scanf("%d",&v);
            int zero = (v==0);
            int idx=i*(M+1)+j;
            pref[idx] = pref[(i-1)*(M+1)+j] + pref[i*(M+1)+j-1] - pref[(i-1)*(M+1)+j-1] + zero;
        }
    }
    int Q; scanf("%d",&Q);
    while(Q--){
        int A,B,C,D; scanf("%d %d %d %d",&A,&B,&C,&D);
        int zeros = pref[C*(M+1)+D] - pref[(A-1)*(M+1)+D] - pref[C*(M+1)+B-1] + pref[(A-1)*(M+1)+B-1];
        printf("%d\n", zeros?0:1);
    }
    free(pref);
    return 0;
}

