import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();
        int M = fs.nextInt();
        int[][] pref = new int[N+1][M+1];
        for(int i=1;i<=N;i++){
            for(int j=1;j<=M;j++){
                int v = fs.nextInt();
                int zero = (v==0)?1:0;
                pref[i][j] = pref[i-1][j] + pref[i][j-1] - pref[i-1][j-1] + zero;
            }
        }
        int Q = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        for(int q=0;q<Q;q++){
            int A = fs.nextInt();
            int B = fs.nextInt();
            int C = fs.nextInt();
            int D = fs.nextInt();
            int zeros = pref[C][D] - pref[A-1][D] - pref[C][B-1] + pref[A-1][B-1];
            sb.append(zeros>0?0:1).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){ in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if(ptr>=len){ len = in.read(buffer); ptr = 0; if(len==-1) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign=1, val=0;
            do{ c = readByte(); } while(c<= ' ');
            if(c=='-'){ sign=-1; c=readByte(); }
            while(c> ' '){ val = val*10 + (c-'0'); c = readByte(); }
            return val*sign;
        }
    }
}

